def sequence(n):
    if n < 2:
        return n

    n_1 = 0
    n_2 = 1

    for _ in range(2, n + 1):
        n_2, n_1 = n_2 + 1 + n_1, n_2

    return n_2 - 1 if n % 2 == 0 else n_2

def pos_count(test_list):
    pos_count = 0
    for x in test_list:
        if x > 0:
            pos_count += 1
    return pos_count

def common_in_nested_lists(nested_lists):
    out = set()
    for nested_list in nested_lists:
        for num in nested_list:
            if num in out:
                continue
            elif num in nested_lists[-1]:
                out.add(num)
    return out

