import math

def angle_complex(real, img):
    result = 0
    if real == 0:
        result = math.pi / 2 if img > 0 else -math.pi / 2
    elif img == 0:
        result = math.pi if real > 0 else 0
    elif real == -img:
        result = -math.pi
    elif real > 0 and img >= 0:
        result = 2 * math.pi + math.atan2(img, real)
    elif real > 0 and img < 0:
        result = 2 * math.pi + math.atan2(img, real)
    elif real < 0 and img > 0:
        result = 2 * math.pi + math.atan2(img, real)
    elif real < 0 and img < 0:
        result = 2 * math.pi + math.atan2(img, real)
    return result

