import math

def volume_sphere(radius):
    return (4/3) * math.pi * (radius ** 3)

def check(n):
    double_reverse = 2 * int(str(n)[::-1])
    if double_reverse - 1 == n:
        return True
    else:
        return False

def recursive_list_sum(a):
    ans = 0
    for i in a:
        if type(i) == list:
            ans += recursive_list_sum(i)
        else:
            ans += i
    return ans

